
class Status {final String apiVersion; final String kind; final String? status; final String? message; final String? reason; final StatusDetails? details; final int? code; Status({this.apiVersion = 'v1', this.kind = 'Status', this.status, this.message, this.reason, this.details, this.code}); factory Status.fromJson(Map<String, dynamic> json) {return Status(apiVersion: json['apiVersion'] ?? 'v1', kind: json['kind'] ?? 'Status', status: json['status'], message: json['message'], reason: json['reason'], details: json['details'] != null ? StatusDetails.fromJson(json['details']) : null, code: json['code']);} Map<String, dynamic> toJson() {return {'apiVersion' : apiVersion, 'kind' : kind, if (status != null) 'status' : status, if (message != null) 'message' : message, if (reason != null) 'reason' : reason, if (details != null) 'details' : details!.toJson(), if (code != null) 'code' : code};}}
